@startuml
title netnotes

class User {
  String name
  String email
}

class Shelf {
  String name
}

class Note {
  String title
  String body
}

class Article {
  String title
  String url
}

class Tag {
  String body
}

User --> User : followes
User --> Shelf : likes
User --> Shelf : creates
User --> Note : creates
User --> Note : likes
User --> Article : finds
User --> Article : likes
User --> Article : followes

Shelf *-- Note : contains
Shelf o-- Note : contains
Shelf *-- Article : contains
Shelf o-- Article : contains

Note *-- Tag : attaches
Article *-- Tag : attaches
Shelf --> Tag : attaches

@enduml
